import { useEffect, useState } from "react";
import { getDailySales, getMonthlySales, getTopProducts } from "../services/api";
import "../css/Reports.css";

function Reports() {
  const [dailySales, setDailySales] = useState([]);
  const [monthlySales, setMonthlySales] = useState([]);
  const [topProducts, setTopProducts] = useState([]);

  const loadReports = async () => {
    try {
      const [dailyRes, monthlyRes, topRes] = await Promise.all([
        getDailySales(),
        getMonthlySales(),
        getTopProducts(),
      ]);
      setDailySales(dailyRes.data || []);
      setMonthlySales(monthlyRes.data || []);
      setTopProducts(topRes.data || []);
    } catch (error) {
      setDailySales([]);
      setMonthlySales([]);
      setTopProducts([]);
    }
  };

  useEffect(() => {
    loadReports();
  }, []);

  return (
    <section className="reports-page">
      <div className="container-fluid">
        <div className="reports-header mb-4">
          <h2 className="reports-title">Sales Reports</h2>
          <p className="reports-subtitle">Track daily, monthly, and top selling product trends.</p>
        </div>

        <div className="row g-4">
          <div className="col-lg-4">
            <div className="card border-0 shadow-sm report-card">
              <div className="card-body">
                <h5 className="report-card-title">Daily Sales</h5>
                <table className="table table-sm">
                  <thead>
                    <tr>
                      <th>Date</th>
                      <th>Sales</th>
                    </tr>
                  </thead>
                  <tbody>
                    {dailySales.length ? (
                      dailySales.map((item) => (
                        <tr key={item._id}>
                          <td>{item._id}</td>
                          <td>Rs {Number(item.totalSales).toLocaleString("en-IN")}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="2" className="text-center">
                          No data
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <div className="col-lg-4">
            <div className="card border-0 shadow-sm report-card">
              <div className="card-body">
                <h5 className="report-card-title">Monthly Sales</h5>
                <table className="table table-sm">
                  <thead>
                    <tr>
                      <th>Month</th>
                      <th>Sales</th>
                    </tr>
                  </thead>
                  <tbody>
                    {monthlySales.length ? (
                      monthlySales.map((item) => (
                        <tr key={item._id}>
                          <td>{item._id}</td>
                          <td>Rs {Number(item.totalSales).toLocaleString("en-IN")}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="2" className="text-center">
                          No data
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          <div className="col-lg-4">
            <div className="card border-0 shadow-sm report-card">
              <div className="card-body">
                <h5 className="report-card-title">Top Selling Products</h5>
                <table className="table table-sm">
                  <thead>
                    <tr>
                      <th>Product</th>
                      <th>Qty</th>
                    </tr>
                  </thead>
                  <tbody>
                    {topProducts.length ? (
                      topProducts.map((item) => (
                        <tr key={item._id}>
                          <td>{item.productName}</td>
                          <td>{item.totalQuantitySold}</td>
                        </tr>
                      ))
                    ) : (
                      <tr>
                        <td colSpan="2" className="text-center">
                          No data
                        </td>
                      </tr>
                    )}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>
  );
}

export default Reports;
